{
  "parameters": "z.object({ itemName: z.string().default("leather_tunic").describe("Name or display name of the leather protection to equip, e.g., leather_tunic") })",
  "executionArgs": {
    "itemName": "leather_tunic"
  },
  "code": "if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Cannot equip item because the bot is not alive.';
}

const normalize = function (val) {
  return String(val).trim().toLowerCase().replace(/^minecraft:/, '').replace(/\s+/g, '_');
};

const requestedName = normalize(args.itemName);
const items = bot.inventory.items();

const armorItem = items.find(function (item) {
  const nameMatch = normalize(item.name) === requestedName;
  const displayMatch = item.displayName && normalize(item.displayName) === requestedName;
  const chestplateGeneric = requestedName.includes('tunic') && item.name.includes('chestplate');
  return nameMatch || displayMatch || chestplateGeneric;
});

if (!armorItem) {
  return '<NO ITEM>: Could not find ' + args.itemName + ' in inventory.';
}

const destination = 'torso';

try {
  await bot.equip(armorItem, destination);
  return '<DONE>: Equipped ' + (armorItem.displayName || armorItem.name) + ' to ' + destination + '.';
} catch (err) {
  return '<INVALID>: Failed to equip ' + (armorItem.displayName || armorItem.name) + ': ' + err.message;
}"
}
